var query = ($json.query || '').trim();
var queryLower = query.toLowerCase();
var telefone = ($json.telefone || '').replace('@s.whatsapp.net', '');

var action = 'listar';

if (queryLower.indexOf('crear') > -1 || queryLower.indexOf('criar') > -1 || queryLower.indexOf('agregar') > -1 || queryLower.indexOf('nueva') > -1 || queryLower.indexOf('nova') > -1 || queryLower.indexOf('adicionar') > -1 || queryLower.indexOf('add') > -1) {
  action = 'crear';
} else if (queryLower.indexOf('eliminar') > -1 || queryLower.indexOf('borrar') > -1 || queryLower.indexOf('excluir') > -1 || queryLower.indexOf('apagar') > -1 || queryLower.indexOf('delete') > -1 || queryLower.indexOf('remover') > -1 || queryLower.indexOf('deletar') > -1) {
  action = 'eliminar';
}

var stopWords = ['crear','criar','agregar','nueva','nuevo','novo','nova','adicionar','add','eliminar','borrar','excluir','apagar','delete','remover','deletar','categoria','categorias','categoría','categorías','la','el','una','um','uma','un','de','por','favor','puede','puedes','listar','ver','mostrar','mis','meus','minhas','quero','quiero','nome','nombre','então','entonces','entao'];

var words = queryLower.replace(/[?!.,;:]/g, '').split(/\s+/);
var significant = [];
for (var i = 0; i < words.length; i++) {
  if (words[i].length > 1 && stopWords.indexOf(words[i]) === -1) {
    significant.push(words[i]);
  }
}

var nombre = '';
for (var j = 0; j < significant.length; j++) {
  var w = significant[j];
  nombre += w.charAt(0).toUpperCase() + w.slice(1);
  if (j < significant.length - 1) nombre += ' ';
}

return [{ json: { action: action, nombre: nombre, telefone: telefone } }];

var parsed = $node['Parsear Query'].json;
var resposta = $input.first().json;
var action = parsed.action;
var categorias = resposta.categorias || [];

if (action === 'listar') {
  if (categorias.length === 0) {
    return [{ json: { skip: true, mensagem: '📂 No tienes categorías creadas todavía.' } }];
  }
  var lista = '';
  for (var i = 0; i < categorias.length; i++) {
    lista += '• ' + categorias[i].nombre + '\n';
  }
  return [{ json: { skip: true, mensagem: '📂 *Tus Categorías:*\n\n' + lista.trim() } }];
}

if (action === 'crear') {
  if (!parsed.nombre) {
    return [{ json: { skip: true, mensagem: '⚠️ Necesito el nombre. Ejemplo: crear categoría Supermercado' } }];
  }
  return [{ json: { skip: false, action: 'crear', nombre: parsed.nombre, telefone: parsed.telefone } }];
}

if (action === 'eliminar') {
  var searchName = (parsed.nombre || '').toLowerCase();
  var match = null;
  for (var j = 0; j < categorias.length; j++) {
    if (categorias[j].nombre && categorias[j].nombre.toLowerCase().indexOf(searchName) > -1) {
      match = categorias[j];
      break;
    }
  }
  if (!match) {
    var lista2 = '';
    for (var k = 0; k < categorias.length; k++) {
      lista2 += '• ' + categorias[k].nombre + '\n';
    }
    return [{ json: { skip: true, mensagem: '🔍 No encontré "' + parsed.nombre + '". Categorías disponibles:\n\n' + (lista2.trim() || 'Ninguna') } }];
  }
  return [{ json: { skip: false, action: 'eliminar', categoria_id: match.id, nombre: match.nombre, telefone: parsed.telefone } }];
}

return [{ json: { skip: true, mensagem: '⚠️ Usa: ver categorías, crear categoría X, eliminar categoría X' } }];

var resposta = $input.first().json;

if (resposta.mensagem) {
  return [{ json: { success: true, message: resposta.mensagem } }];
}

if (resposta.success) {
  return [{ json: { success: true, message: resposta.message || '✅ Operación completada.' } }];
}

return [{ json: { success: false, message: '❌ Error: ' + (resposta.error || 'Algo salió mal.') } }];
